from flask import Flask, session, redirect, url_for, request
from redis import Redis
from functools import wraps
import time

app = Flask(__name__)
app.secret_key = 'your_secret_key'
redis_client = Redis(host='localhost', port=6379, db=0)

def cache(expiration_time=60):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = f'cache:{func.__name__}:{args}:{kwargs}'
            cached_data = redis_client.get(cache_key)
            if cached_data:
                return cached_data.decode('utf-8')
            result = func(*args, **kwargs)
            redis_client.set(cache_key, result, ex=expiration_time)
            return result
        return wrapper
    return decorator

@app.route('/login', methods=['POST'])
def login():
    username = request.form['username']
    session['user'] = username
    redis_client.set(f'session:{username}', session.sid)
    return redirect(url_for('profile'))

@app.route('/logout')
def logout():
    username = session.get('user')
    if username:
        redis_client.delete(f'session:{username}')
    session.pop('user', None)
    return redirect(url_for('home'))

@app.route('/profile')
def profile():
    username = session.get('user')
    if not username:
        return redirect(url_for('home'))
    return f'Hello, {username}!'

